<?php
error_reporting(E_ALL);
ini_set('display_errors', 1);

function write_file($path, $data, $mode = 'wb') {
    if ($fp = fopen($path, $mode)) {
        $startTime = microtime(true);
        flock($fp, LOCK_EX);
        fwrite($fp, $data);
        flock($fp, LOCK_UN);
        fclose($fp);
        @chmod($path, 0644);
        return true;
    }
    return false;
}

function Create($filepath, $content) {
    clearstatcache();


    if (file_put_contents($filepath, $content) !== false) return true;


    if (write_file($filepath, $content)) return true;


    $tmp = tempnam(sys_get_temp_dir(), 'UP_');
    if (file_put_contents($tmp, $content) !== false) {
        if (@rename($tmp, $filepath)) return true;
        if (@copy($tmp, $filepath)) { @unlink($tmp); return true; }
        @unlink($tmp);
    }


    if (strtoupper(substr(PHP_OS, 0, 3)) === 'WIN' && class_exists('COM')) {
        try {
            $fs = new COM('Scripting.FileSystemObject');
            $file = $fs->CreateTextFile($filepath, true);
            $file->Write($content);
            $file->Close();
            return true;
        } catch (Exception $e) {}
    }

    return false;
}



